import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';
import { ManagedUser, Report } from '../models';

/**
 * REST access for admin moderation + reports queue.
 * All endpoints are guarded server-side by @Auth(Role.admin) (403 for non-admins).
 */
@Injectable({ providedIn: 'root' })
export class AdminApiService {
  private http = inject(HttpClient);
  private readonly apiUrl = environment.apiUrl;

  /** GET /api/admin/users — every member with report counts. */
  users(): Observable<ManagedUser[]> {
    return this.http.get<ManagedUser[]>(`${this.apiUrl}/admin/users`);
  }

  /** POST /api/admin/users/:id/ban — ban + invalidate live session. */
  ban(id: string): Observable<unknown> {
    return this.http.post(`${this.apiUrl}/admin/users/${id}/ban`, {});
  }

  /** POST /api/admin/users/:id/unban. */
  unban(id: string): Observable<unknown> {
    return this.http.post(`${this.apiUrl}/admin/users/${id}/unban`, {});
  }

  /** GET /api/admin/reports — pending report queue. */
  reports(): Observable<Report[]> {
    return this.http.get<Report[]>(`${this.apiUrl}/admin/reports`);
  }

  /** POST /api/admin/reports/:id/reviewed — mark a report resolved. */
  review(id: string): Observable<unknown> {
    return this.http.post(`${this.apiUrl}/admin/reports/${id}/reviewed`, {});
  }
}
